<template><div v-if="open" class="m-modal" @click.self="$emit('close')"><section class="m-sheet"><div class="m-sheet-head"><div><h2>商户反馈</h2><p class="muted">订单通知、定位、商品管理问题都可以反馈。</p></div><button class="m-btn secondary" @click="$emit('close')">关闭</button></div><div class="m-form"><label class="m-field full">描述<textarea v-model="form.description" class="m-textarea"></textarea></label><label class="m-field">联系人<input v-model="form.contact_name" class="m-input"></label><label class="m-field">手机号<input v-model="form.contact_phone" class="m-input" placeholder="请输入手机号"></label><label class="m-field full">图片<input type="file" class="m-input" accept="image/*" @change="readImage"></label></div><div v-if="result" class="m-result">{{ result }}</div><div v-if="error" class="m-result error">{{ error }}</div><div class="m-actions"><button class="m-btn secondary" @click="$emit('close')">取消</button><button class="m-btn primary" :disabled="submitting" @click="submit">{{ submitting ? '提交中…' : '提交反馈' }}</button></div></section></div></template>
<script setup>import { reactive, ref, watch } from 'vue'; import { apiFetch, merchantHeaders } from '../../../api/client'; const props=defineProps({open:Boolean, defaults:Object}); defineEmits(['close']); const form=reactive({description:'',contact_name:'',contact_phone:'',image_url:''}); const error=ref(''); const result=ref(''); const submitting=ref(false); watch(()=>props.open,(open)=>{ if(open){ form.contact_name ||= props.defaults?.name || ''; form.contact_phone ||= props.defaults?.phone || ''; error.value=''; result.value='' }}); function validPhone(phone){ const d=String(phone||'').replace(/\D/g,''); return (d.length===11&&d.startsWith('1'))||d.length===8||(d.length===11&&d.startsWith('852')) } function readImage(e){ const f=[...(e.target.files||[])].find(x=>x.type.startsWith('image/')); if(!f)return; const r=new FileReader(); r.onload=()=>{form.image_url=String(r.result||'')}; r.readAsDataURL(f)} async function submit(){ if(!form.description||!form.contact_phone){error.value='请填写描述和手机号';return} if(!validPhone(form.contact_phone)){error.value='请输入有效手机号';return} submitting.value=true; error.value=''; result.value=''; try{ await apiFetch('/api/feedback',{method:'POST',headers:merchantHeaders(),body:JSON.stringify({source:'merchant',...form,page_url:location.pathname+location.search})}); result.value='反馈已提交，平台会尽快处理。'; form.description=''; form.image_url='' }catch(e){error.value=e.message||'提交失败'}finally{submitting.value=false} }</script>
